if (soundBtn) {
  soundBtn.addEventListener("click", () => {
    state.soundEnabled = !state.soundEnabled;
    soundBtn.classList.toggle("active", state.soundEnabled);
    soundBtn.title = state.soundEnabled ? "Sound alerts ON" : "Sound alerts OFF";

